// bench_persist: sweep over a range of |X| sizes, serialize each (Y, curve)
// pair, and print a table of persisted-file bytes vs raw |X| bytes.
//
// Y is always built by DeterministicYBuilder (so persistence only needs the
// seed + length, not the full Y bytes). X is generated by the same portable
// splitmix64 used elsewhere in the suite, so this program is reproducible
// across runs and machines.
//
// Usage:
//   bench_persist                            # human-readable table only
//   bench_persist --out-json <path>          # also emit per-case curve data
//
// Output: one CSV-ish row per case to stdout, plus the JSON sidecar when
// requested. The JSON has one element per case containing meta + a sampled
// (i, j) point list suitable for plotting; for cases with more than
// kPointBudget nodes the points are evenly-spaced subsampled so a chart
// doesn't degrade.

#include <cstdint>
#include <cstdio>
#include <fstream>
#include <iomanip>
#include <iostream>
#include <sstream>
#include <string>
#include <vector>

#include "curve_codec.hpp"
#include "curve_locator.hpp"
#include "y_builder.hpp"

namespace dac = algorithms::dac;

namespace {

std::vector<std::uint8_t> make_x(std::size_t n, std::uint64_t seed) {
    std::vector<std::uint8_t> x;
    x.reserve(n);
    std::uint64_t state = seed;
    for (std::size_t i = 0; i < n; ++i) {
        x.push_back(static_cast<std::uint8_t>(
            dac::DeterministicYBuilder::splitmix64(state) & 0xFFULL));
    }
    return x;
}

struct Case {
    std::size_t x_len;
    std::size_t y_len;
    std::uint64_t y_seed;
    std::uint64_t x_seed;
};

struct CaseResult {
    std::size_t x_len;
    std::size_t y_len;
    std::uint8_t index_width;
    std::uint64_t file_bytes;
    double ratio;
    bool round_trip_ok;
    std::vector<std::pair<std::size_t, std::int64_t>> sampled_points;  // (i, j)
};

// Chart point budget: dense scatter plots above this become unreadable, so
// large curves are evenly subsampled before being charted. Round-trip and
// size measurement still use the full curve.
constexpr std::size_t kPointBudget = 512;

std::vector<std::pair<std::size_t, std::int64_t>>
subsample(const std::vector<std::int64_t>& nodes) {
    std::vector<std::pair<std::size_t, std::int64_t>> out;
    const std::size_t n = nodes.size();
    if (n == 0) {
        return out;
    }
    if (n <= kPointBudget) {
        out.reserve(n);
        for (std::size_t k = 0; k < n; ++k) {
            out.emplace_back(k + 1, nodes[k]);
        }
        return out;
    }
    // Evenly spaced indices, always including first and last.
    out.reserve(kPointBudget);
    for (std::size_t s = 0; s < kPointBudget; ++s) {
        const std::size_t k = (s * (n - 1)) / (kPointBudget - 1);
        out.emplace_back(k + 1, nodes[k]);
    }
    return out;
}

CaseResult run_case(const Case& c) {
    const auto y = dac::DeterministicYBuilder::build(c.y_seed, c.y_len);
    const auto x = make_x(c.x_len, c.x_seed);

    const auto curve = dac::CurveLocator::locate(x, y);

    // Serialize to an in-memory buffer to measure bytes-on-the-wire without
    // touching the filesystem.
    std::stringstream buf(std::ios::in | std::ios::out | std::ios::binary);
    dac::CurveCodec::serialize(buf, c.y_seed, y.size(), curve);
    const std::string blob = buf.str();
    const std::uint64_t file_bytes = blob.size();
    const std::uint64_t predicted = dac::CurveCodec::persisted_size(x.size(), y.size());

    // Round-trip sanity: deserialize, then decode X from (Y, curve) and
    // confirm bytewise equality with the original X. If this fails the
    // measured size is meaningless.
    std::stringstream readback(blob, std::ios::in | std::ios::out | std::ios::binary);
    const auto rt = dac::CurveCodec::deserialize(readback);
    bool ok = (rt.curve.length() == x.size()) && (rt.y == y);
    if (ok) {
        for (std::size_t i = 1; i <= x.size(); ++i) {
            if (rt.y[rt.curve.evaluate_at_node(i)] != x[i - 1]) {
                ok = false;
                break;
            }
        }
    }

    const std::uint8_t w = dac::CurveCodec::pick_index_width(y.size());
    const double ratio = x.size() == 0 ? 0.0
        : static_cast<double>(file_bytes) / static_cast<double>(x.size());

    std::printf("| %8zu | %8zu | %u | %12llu | %12llu | %6.3fx | %s |\n",
                x.size(),
                y.size(),
                static_cast<unsigned>(w),
                static_cast<unsigned long long>(file_bytes),
                static_cast<unsigned long long>(predicted),
                ratio,
                ok ? "ok" : "ROUND-TRIP FAILED");

    CaseResult cr;
    cr.x_len = x.size();
    cr.y_len = y.size();
    cr.index_width = w;
    cr.file_bytes = file_bytes;
    cr.ratio = ratio;
    cr.round_trip_ok = ok;
    cr.sampled_points = subsample(curve.nodes());
    return cr;
}

void emit_json(std::ostream& out, const std::vector<CaseResult>& results) {
    out << "{\n  \"point_budget\": " << kPointBudget << ",\n  \"cases\": [\n";
    for (std::size_t i = 0; i < results.size(); ++i) {
        const auto& r = results[i];
        out << "    {\n";
        out << "      \"x_len\": " << r.x_len << ",\n";
        out << "      \"y_len\": " << r.y_len << ",\n";
        out << "      \"index_width\": " << static_cast<int>(r.index_width) << ",\n";
        out << "      \"file_bytes\": " << r.file_bytes << ",\n";
        out << "      \"ratio\": " << r.ratio << ",\n";
        out << "      \"round_trip\": " << (r.round_trip_ok ? "true" : "false") << ",\n";
        out << "      \"points\": [";
        for (std::size_t k = 0; k < r.sampled_points.size(); ++k) {
            if (k) out << ", ";
            out << "[" << r.sampled_points[k].first << ", "
                << r.sampled_points[k].second << "]";
        }
        out << "]\n    }";
        if (i + 1 < results.size()) out << ",";
        out << "\n";
    }
    out << "  ]\n}\n";
}

}  // namespace

int main(int argc, char** argv) {
    std::string json_path;
    for (int i = 1; i < argc; ++i) {
        std::string arg = argv[i];
        if (arg == "--out-json" && i + 1 < argc) {
            json_path = argv[++i];
        }
    }

    std::printf("| %8s | %8s | %s | %12s | %12s | %7s | %s |\n",
                "|X|", "|Y|", "W", "file_bytes", "predicted", "ratio", "round-trip");
    std::printf("|----------|----------|---|--------------|--------------|---------|------------|\n");

    std::vector<CaseResult> results;
    auto record = [&](const Case& c) { results.push_back(run_case(c)); };

    // Fixed minimum Y (768 = 256*3): the asymptote is index_width=2 -> 2.0x.
    for (std::size_t n : {1u, 5u, 10u, 100u, 1024u, 4096u, 10240u}) {
        record({n, 768, 0xC0FFEEULL, 0xDEADBEEFULL ^ n});
    }
    std::printf("|----------|----------|---|--------------|--------------|---------|------------|\n");
    // Larger Y, still within W=2 budget (y_length-1 < 65536).
    for (std::size_t n : {1024u, 4096u, 10240u}) {
        record({n, 16384, 0xC0FFEEULL, 0xDEADBEEFULL ^ n ^ 0x1u});
    }
    std::printf("|----------|----------|---|--------------|--------------|---------|------------|\n");
    // Y just above the W=2 threshold (y_length-1 >= 65536) -> W jumps to 4
    // and the persisted-bytes ratio doubles.
    for (std::size_t n : {1024u, 4096u, 10240u}) {
        record({n, 65792, 0xC0FFEEULL, 0xDEADBEEFULL ^ n ^ 0x2u});
    }

    std::printf("\nNotes\n");
    std::printf("  * |X|        = raw input length in bytes\n");
    std::printf("  * |Y|        = Y length used by the locator (built deterministically from y_seed)\n");
    std::printf("  * W          = bytes per index in the persisted file (1/2/4/8, auto-sized)\n");
    std::printf("  * file_bytes = total bytes written by CurveCodec::serialize\n");
    std::printf("  * predicted  = 32 + |X| * W  (header + index array)\n");
    std::printf("  * ratio      = file_bytes / |X|; for large N this converges to W exactly\n");

    if (!json_path.empty()) {
        std::ofstream out(json_path);
        if (!out) {
            std::fprintf(stderr, "bench_persist: cannot open %s for writing\n", json_path.c_str());
            return 1;
        }
        emit_json(out, results);
        std::fprintf(stderr, "bench_persist: wrote %s (%zu cases)\n",
                     json_path.c_str(), results.size());
    }
    return 0;
}
